import Link from "next/link";import {CheckCircle2,Clock3} from "lucide-react";import {requireUser} from "@/src/lib/auth/session";import {createSupabaseServerClient} from "@/src/lib/supabase/server";
export const dynamic="force-dynamic";
export default async function MembershipSuccessPage({searchParams}:{searchParams:Promise<{session_id?:string}>}){await requireUser();const id=(await searchParams).session_id;const valid=id&&/^cs_(test_|live_)?[A-Za-z0-9]+$/.test(id);const supabase=await createSupabaseServerClient();const {data}=valid?await supabase.from("vendor_memberships").select("status,vendor_membership_levels(name)").eq("stripe_checkout_session_id",id).maybeSingle():{data:null};const active=data&&["active","trialing"].includes(data.status);const level=data?.vendor_membership_levels as unknown as {name:string}|null;return <main className="grid min-h-[70vh] place-items-center p-5"><section className="max-w-xl rounded-[2rem] border border-slate-200 bg-white p-8 text-center shadow-sm">{active?<CheckCircle2 className="mx-auto size-12 text-emerald-600"/>:<Clock3 className="mx-auto size-12 text-amber-600"/>}<h1 className="mt-5 text-3xl font-semibold">{active?"Payment confirmed":"Membership processing"}</h1><p className="mt-3 text-sm leading-6 text-slate-600">{active?`${level?.name??"Your membership"} was verified through Stripe. Complete your business profile next; payment alone does not publish the organization.`:"The URL is not proof of payment. This page updates only after the signed Stripe webhook records the subscription."}</p><Link href={active?"/vendor/profile":"/vendor/membership"} className="mt-6 inline-flex min-h-11 items-center rounded-full bg-slate-950 px-5 text-sm font-bold text-white">{active?"Complete business profile":"View membership"}</Link></section></main>}
